local LxBaseMgr = require("LApp.manager.LxBaseMgr")
---@class LxAdapterMgr:LxBaseMgr
local LxAdapterMgr = classX("LxAdapterMgr", LxBaseMgr)

function LxAdapterMgr:Initialize()
    LxBaseMgr.Initialize(self)

    ---@type table<string,LxBaseAdapter>
    self._adapters = {}
    self._levelNames = {}
    self:AddAdapter(LevelNames.Loader, require("LApp.adapter.LxLoaderAdapter"):New())
    self:AddAdapter(LevelNames.Empty, require("LApp.adapter.LxEmptyAdapter"):New())
    self:AddAdapter(LevelNames.Update, require("LApp.adapter.LxUpdateAdapter"):New())
    self:AddAdapter(LevelNames.Main, require("LApp.adapter.LxMainAdapter"):New())
    self:AddAdapter(LevelNames.Login, require("LApp.adapter.LxLoginAdapter"):New())
end

function LxAdapterMgr:Dispose()
    local adapters = self._adapters
    if adapters then
        for _k,v in pairs(self._levelNames) do
            local adapter = adapters[v]
            adapter:Dispose()
            adapters[v] = v
        end
        self._adapters = nil
    end
    LxBaseMgr.Dispose(self)
end

function LxAdapterMgr:AddAdapter(level, adapter)
    table.insert(self._levelNames, level)
    adapter:Initialize()
    self._adapters[level] = adapter
end

---@return LxBaseAdapter
function LxAdapterMgr:GetAdapter(level)
    return self._adapters[level]
end

function LxAdapterMgr:RemoveAdapter(level)
    table.removebyvalue(self._levelNames, level)
    local adapter = self._adapters[level]
    self._adapters[level] = nil
    return adapter
end


